css_template:
#{{ID}} .utk-container {
    position: absolute;
    bottom: 0;
    left: 0;
    width: var(--v-width, 100%);
    min-height: var(--v-height, 60px);
    background: {{PRIMARY_BG}};
    display: flex;
    align-items: center;
    overflow: hidden;
    border: {{BORDER_WIDTH}}px solid {{BORDER_COLOR}};
    border-radius: {{BORDER_RADIUS}}px;
    box-sizing: border-box;
    font-family: '{{FONT_FAMILY}}', sans-serif;
    opacity: 0;
    transform: translateY(100px);
    box-shadow: {{BOX_SHADOW}};
}
/* --- WIPER --- */
#{{ID}} .utk-wiper {
    position: absolute;
    left: 0;
    min-width: 150px;
    width: auto;
    padding: 0 40px;
    height: 100%;
    background: {{WIPER_BG}};
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 5px 0 15px rgba(0,0,0,0.5);
    border-radius: {{BORDER_RADIUS}}px;
    z-index: 10;
    box-sizing: border-box;
    overflow: hidden;
    flex-shrink: 0;
}
#{{ID}} .utk-wiper-gleam {
    position: absolute;
    top: 0;
    left: -100%;
    width: 60%;
    height: 100%;
    display: {{#if WIPER_GLEAM_ENABLED}}block{{else}}none{{/if}};
    background: {{WIPER_GLEAM_BG}};
    transform: skewX(-20deg);
    pointer-events: none;
    animation: utk-gleam {{WIPER_GLEAM_DURATION}}s infinite ease-in-out;
}
#{{ID}} .utk-wiper-text {
    font-weight: {{WIPER_FONT_WEIGHT}};
    font-size: {{WIPER_FONT_SIZE}}px;
    font-family: {{WIPER_FONT}}, sans-serif;
    color: {{WIPER_TEXT_COLOR}};
    letter-spacing: {{WIPER_LETTER_SPACING}}px;
    position: relative;
    z-index: 1;
    white-space: nowrap;
}
/* --- TRYB: POZIOMY (scroll) --- */
#{{ID}} .utk-track-wrap {
    flex: 1;
    overflow: hidden;
    height: 100%;
    align-items: center;
}
#{{ID}} .utk-ticker-track {
    display: flex;
    align-items: center;
    white-space: nowrap;
    height: 100%;
    padding-left: 100%;
}
#{{ID}} .utk-ticker-item {
    color: {{TITLE_COLOR}};
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    padding: {{PADDING_Y}}px 20px;
    white-space: nowrap;
}
#{{ID}} .utk-ticker-sep {
    {{SEPARATOR_CSS}}
}
/* --- TRYB: PIONOWY --- */
#{{ID}} .utk-single-wrap {
    flex: 1;
    height: 100%;
    position: relative;
    overflow: hidden;
}
#{{ID}} .utk-viewport {
    width: 100%;
    height: 100%;
    position: relative;
    overflow: hidden;
}
#{{ID}} .utk-single-text {
    position: absolute;
    width: 100%;
    height: 100%;
    display: flex;
    align-items: center;
    padding: 0 20px;
    box-sizing: border-box;
    color: {{TITLE_COLOR}};
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    white-space: nowrap;
    transition: opacity 0.4s ease-in-out;
    opacity: 0;
}
#{{ID}} .utk-single-text.visible {
    opacity: 1;
}
/* --- WHIP ANIMATIONS --- */
#{{ID}} .utk-wiper.move-right {
    animation: utk-wiper-slide-right 1s linear forwards;
}
#{{ID}} .utk-wiper.snap-back {
    animation: utk-wiper-snap-back 0.5s ease-in-out forwards;
}
@keyframes utk-wiper-slide-right {
    0%   { left: 0%; }
    100% { left: calc(var(--v-width, 100%) - var(--wiper-w, 170px)); }
}
@keyframes utk-wiper-snap-back {
    0%   { left: calc(var(--v-width, 100%) - var(--wiper-w, 170px)); }
    100% { left: 0%; }
}
@keyframes utk-gleam {
    0%   { left: -100%; }
    100% { left: 200%; }
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container  = root.querySelector('.utk-container');
    const wiper      = root.querySelector('.utk-wiper');
    const wiperTextEl= root.querySelector('.utk-wiper-text');
    const gleamEl    = root.querySelector('.utk-wiper-gleam');
    const dataEl     = root.querySelector('#f-news-list');
    const trackWrap  = root.querySelector('.utk-track-wrap');
    const singleWrap = root.querySelector('.utk-single-wrap');
    const singleText = root.querySelector('.utk-single-text');
    const tickerTrack= root.querySelector('.utk-ticker-track');

    if (!container || !dataEl) return;

    const MODE = "{{TICKER_MODE}}" || "whip"; // whip | horizontal | vertical
    const DEFAULT_WIPER = "{{WIPER_TEXT}}";
    const WIPER_SHOW = "{{WIPER_SHOW}}" !== "false";

    let items = [];
    try { items = JSON.parse(dataEl.textContent || '[]'); } catch(e) { console.error('Error parsing ITEMS json', e); } 
    if (!items.length) items = ['BRAK WIADOMOŚCI'];

    const getText = (item) => (typeof item === 'object') ? (item.text || '') : item;
    const getCat  = (item) => (typeof item === 'object') ? (item.category || '') : '';

    let currentIndex = 0;
    let cycleRunning = false;
    let activeTimeouts = [];
    let cycleTimer = null;

    // Ustaw widoczne panele
    function setupLayout() {
        if (MODE === 'horizontal') {
            trackWrap.style.display  = 'flex';
            singleWrap.style.display = 'none';
        } else {
            trackWrap.style.display  = 'none';
            singleWrap.style.display = 'flex';
        }
    }

    function getWiperWidth() {
        return (wiper && wiper.style.display !== 'none') ? wiper.offsetWidth : 0;
    }

    function updateWiper(label) {
        const show = WIPER_SHOW && !!(label && label.trim());
        if (wiper) {
            wiper.style.display = show ? 'flex' : 'none';
            if (wiperTextEl) wiperTextEl.innerText = show ? label : '';
        }
        container.style.setProperty('--wiper-w', getWiperWidth() + 'px');
    }

    function adjustFontSingleText(el) {
        const base = parseFloat("{{TITLE_SIZE}}") || 40;
        const wiperW = getWiperWidth();
        const maxW = container.offsetWidth - wiperW - 40;
        el.style.paddingLeft = (wiperW > 0 ? wiperW + 20 : 20) + 'px';
        el.style.fontSize = base + 'px';
        let newSize = base;
        if (maxW > 0 && el.scrollWidth > maxW && el.scrollWidth > 0) {
            newSize = Math.min((maxW / el.scrollWidth) * base, base);
        }
        el.style.fontSize = Math.max(newSize, 10) + 'px';
    }

    // ============ TRYB: WHIP ============
    function runWhip() {
        if (!cycleRunning) return;
        singleText.classList.remove('visible');

        const item = items[currentIndex];
        const text = getText(item);
        const cat  = getCat(item);
        singleText.innerHTML = text;
        const label = cat || DEFAULT_WIPER;
        updateWiper(label);
        adjustFontSingleText(singleText);

        activeTimeouts.push(setTimeout(() => {
            if (!cycleRunning) return;
            singleText.classList.add('visible');
        }, 100));

        activeTimeouts.push(setTimeout(() => {
            if (!cycleRunning) return;
            singleText.classList.remove('visible');
            activeTimeouts.push(setTimeout(() => {
                if (!cycleRunning) return;
                if (wiper && wiper.style.display !== 'none') {
                    wiper.className = 'utk-wiper move-right';
                }
                activeTimeouts.push(setTimeout(() => {
                    if (!cycleRunning) return;
                    if (wiper && wiper.style.display !== 'none') {
                        wiper.className = 'utk-wiper snap-back';
                    }
                    activeTimeouts.push(setTimeout(() => {
                        if (!cycleRunning) return;
                        currentIndex = (currentIndex + 1) % items.length;
                        runWhip();
                    }, 500));
                }, 1000));
            }, 400));
        }, 4000));
    }

    // ============ TRYB: PIONOWY ============
    function runVertical() {
        if (!cycleRunning) return;
        singleText.classList.remove('visible');

        const item = items[currentIndex];
        singleText.innerHTML = getText(item);
        updateWiper(getCat(item) || DEFAULT_WIPER);
        adjustFontSingleText(singleText);

        const displayMs = Math.max(1000, (parseFloat("{{TICKER_SPEED}}") || 5) * 1000);

        activeTimeouts.push(setTimeout(() => {
            if (!cycleRunning) return;
            singleText.classList.add('visible');
        }, 100));

        cycleTimer = setTimeout(() => {
            if (!cycleRunning) return;
            singleText.classList.remove('visible');
            setTimeout(() => {
                if (!cycleRunning) return;
                currentIndex = (currentIndex + 1) % items.length;
                runVertical();
            }, 500);
        }, displayMs);
    }

    // ============ TRYB: POZIOMY ============
    function runHorizontal() {
        if (!tickerTrack) return;
        const trackItems = Array.from(tickerTrack.querySelectorAll('.utk-ticker-item'));
        const itemData = trackItems.map((el, idx) => ({
            el: el,
            offset: el.offsetLeft,
            category: getCat(items[idx]) || DEFAULT_WIPER
        }));
        const trackWidth = tickerTrack.scrollWidth || 0;
        const speedPxPerSec = parseFloat("{{TICKER_SPEED}}") || parseFloat("{{speed}}") || 100;
        const triggerPoint = getWiperWidth() || 150;
        let lastCategory = '';

        // Ustaw wiper na pierwszą kategorię
        const firstCat = (itemData[0] && itemData[0].category) || DEFAULT_WIPER;
        updateWiper(firstCat);
        lastCategory = firstCat;

        if (speedPxPerSec > 0 && trackWidth > 0) {
            const duration = trackWidth / speedPxPerSec;
            gsap.to(tickerTrack, {
                x: -trackWidth,
                duration: duration,
                ease: 'none',
                repeat: -1,
                onUpdate: function() {
                    const currentX = gsap.getProperty(tickerTrack, 'x');
                    let activeCat = DEFAULT_WIPER;
                    for (let i = 0; i < itemData.length; i++) {
                        if (currentX + itemData[i].offset > triggerPoint) {
                            activeCat = itemData[i].category;
                            break;
                        }
                    }
                    if (activeCat !== lastCategory) {
                        lastCategory = activeCat;
                        updateWiper(activeCat);
                    }
                }
            });
        }
    }

    // ============ SHOWslt / HIDE ============
    root.__slt_show = () => {
        cycleRunning = true;
        setupLayout();
        const tl = gsap.timeline();
        tl.to(container, { opacity: 1, y: 0, duration: 0.6, ease: 'power2.out' });
        tl.add(() => {
            if (MODE === 'whip')       runWhip();
            else if (MODE === 'vertical')  runVertical();
            else if (MODE === 'horizontal') runHorizontal();
        }, '+=0.1');
        return tl;
    };

    root.__slt_hide = () => {
        cycleRunning = false;
        activeTimeouts.forEach(t => clearTimeout(t));
        activeTimeouts = [];
        if (cycleTimer) clearTimeout(cycleTimer);
        if (tickerTrack) gsap.killTweensOf(tickerTrack);
        if (gleamEl) gsap.killTweensOf(gleamEl);
        const tl = gsap.timeline();
        tl.to(container, { opacity: 0, y: 100, duration: 0.4, ease: 'power2.in' });
        return tl;
    };

    window.addEventListener('resize', () => {
        if (MODE !== 'horizontal') adjustFontSingleText(singleText);
    });
})();
